/**
 * @import {State} from 'mdast-util-to-markdown'
 * @import {Code} from 'mdast'
 */

/**
 * @param {Code} node
 * @param {State} state
 * @returns {boolean}
 */
export function formatCodeAsIndented(node, state) {
  return Boolean(
    state.options.fences === false &&
      node.value &&
      // If thereŌĆÖs no infoŌĆ”
      !node.lang &&
      // And thereŌĆÖs a non-whitespace characterŌĆ”
      /[^ \r\n]/.test(node.value) &&
      // And the value doesnŌĆÖt start or end in a blankŌĆ”
      !/^[\t ]*(?:[\r\n]|$)|(?:^|[\r\n])[\t ]*$/.test(node.value)
  )
}
